import{c as t,Q as o,j as r,m as a}from"./chunks/framework.CTNaDwNv.js";const _=JSON.parse('{"title":"Iteration loop","description":"","frontmatter":{},"headers":[],"relativePath":"guide/iteration.md","filePath":"guide/iteration.md","lastUpdated":1779853631000}'),i={name:"guide/iteration.md"};function l(d,e,s,c,n,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="iteration-loop" tabindex="-1">Iteration loop <a class="header-anchor" href="#iteration-loop" aria-label="Permalink to &quot;Iteration loop&quot;">​</a></h1><p>How a productive session usually flows once everything&#39;s wired.</p><h2 id="single-file-fix" tabindex="-1">Single-file fix <a class="header-anchor" href="#single-file-fix" aria-label="Permalink to &quot;Single-file fix&quot;">​</a></h2><ol><li><strong>Symptom.</strong> &quot;Players see double mileage in the speedometer.&quot;</li><li>Agent calls <code>read_file({ resource: &quot;speed_hud&quot;, path: &quot;client/main.lua&quot; })</code>.</li><li>Agent calls <code>write_file({ resource: &quot;speed_hud&quot;, path: &quot;client/main.lua&quot;, content: &quot;&lt;patched&gt;&quot; })</code>.</li><li>Agent calls <code>restart_resource({ name: &quot;speed_hud&quot; })</code>.</li><li>Agent calls <code>tail_console({ lines: 20 })</code> to verify no errors on start.</li></ol><p>You confirm in-game; done.</p><h2 id="ui-iteration" tabindex="-1">UI iteration <a class="header-anchor" href="#ui-iteration" aria-label="Permalink to &quot;UI iteration&quot;">​</a></h2><ol><li>Agent edits <code>web/src/App.vue</code>.</li><li>Agent calls <code>run_shell({ resource: &quot;my_res&quot;, command: &quot;npm&quot;, args: [&quot;run&quot;, &quot;build&quot;], cwd: &quot;web&quot;, timeoutMs: 60000 })</code>.</li><li>Agent calls <code>restart_resource({ name: &quot;my_res&quot; })</code>.</li><li>You reopen the UI (F6 / <code>/myres</code>).</li><li>Agent calls <code>screenshot_nui({ resource: &quot;my_res&quot; })</code>.</li><li>Agent reads the PNG, describes what it sees, proposes the next tweak.</li></ol><p>Average loop time on a dev box: ~5–10 seconds per change.</p><h2 id="multi-resource-change" tabindex="-1">Multi-resource change <a class="header-anchor" href="#multi-resource-change" aria-label="Permalink to &quot;Multi-resource change&quot;">​</a></h2><ol><li>Agent picks a name and runs <code>scaffold_fivem_resource_workflow</code> (mandatory grill).</li><li>After your confirmation, agent: <code>create_resource</code>, <code>refresh_resources</code>, <code>run_shell</code> for any UI scaffolding, then a batch of <code>write_file</code> calls.</li><li><code>ensure_resource</code> returns <code>stateAfter === &quot;started&quot;</code> and the post-start console lines.</li><li>If start failed, agent calls <code>tail_console</code> to find the syntax error and offers a single-file fix before re-writing.</li></ol><h2 id="live-player-workflow" tabindex="-1">Live player workflow <a class="header-anchor" href="#live-player-workflow" aria-label="Permalink to &quot;Live player workflow&quot;">​</a></h2><ol><li>You: <code>/agent_test_optin</code>.</li><li>Agent: <code>register_test_subject({ serverId: 1 })</code>.</li><li>Agent: <code>get_player_state({ serverId: 1 })</code> to see coords, ped, health.</li><li>Agent: <code>esx_call_player({ serverId: 1, method: &quot;getInventory&quot; })</code> to see items.</li><li>Agent: <code>client_call_native({ serverId: 1, native: &quot;SetEntityCoords&quot;, args: [&quot;$ped&quot;, 200, -800, 30, false, false, false, true] })</code> to test a teleport.</li><li>Agent: <code>client_call_native({ serverId: 1, native: &quot;GetEntityCoords&quot;, args: [&quot;$ped&quot;, true] })</code> to verify the move.</li></ol><h2 id="what-goes-wrong-how-the-agent-recovers" tabindex="-1">What goes wrong + how the agent recovers <a class="header-anchor" href="#what-goes-wrong-how-the-agent-recovers" aria-label="Permalink to &quot;What goes wrong + how the agent recovers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Tool that catches it</th><th>Recovery path</th></tr></thead><tbody><tr><td>Resource won&#39;t start</td><td><code>ensure_resource</code> returns <code>RESOURCE_FAILED_TO_START</code> + log lines</td><td><code>tail_console</code>, propose fix, ask before re-writing</td></tr><tr><td>Token leaked / suspicious activity</td><td><code>audit log</code> JSONL</td><td>rotate token (<code>rm dist/.agent_token &amp;&amp; restart agent_api</code>)</td></tr><tr><td>Player griefed by a <code>client_call_native</code></td><td>hard <code>agent_api_client_blocked_natives</code></td><td>add native to blocklist, restart</td></tr><tr><td>Rate limit hit</td><td>tool returns <code>RATE_LIMITED</code> with <code>retryAfterMs</code></td><td>back off, then continue</td></tr><tr><td>Multi-step write race</td><td>per-resource lock serialises</td><td>next call waits, no race</td></tr></tbody></table>',14)])])}const g=t(i,[["render",l]]);export{_ as __pageData,g as default};
